// HasAssocs applies the HasEdge predicate on the "assocs" edge.
func HasAssocs() predicate.Printer {
	return predicate.Printer(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, AssocsTable, AssocsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasAssocsWith applies the HasEdge predicate on the "assocs" edge with a given conditions (other predicates).
